#!/usr/bin/env python3
"""
Al enviar una resena en /p/[slug]/cita/[id], ahora aparece un popup
'Gracias por tu resena!' con un boton 'Cerrar' (se queda en la pagina,
ve su resena enviada) y un boton 'Salir' (vuelve al portal del negocio).

Ejecutar desde la raiz del repo (carpeta que contiene 'src'):
    python3 apply_review_thanks_popup.py
"""

import base64
from pathlib import Path

FILES = {
    'src/components/CitaManageClient.tsx': """""",
    'src/components/cita-manage.css': """""",
}

def main():
    for relpath, b64 in FILES.items():
        p = Path(relpath)
        p.write_bytes(base64.b64decode(b64))
        print(f"escrito: {relpath} ({p.stat().st_size} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'Popup de agradecimiento al enviar resena'")
    print("  git push")

if __name__ == "__main__":
    main()